import path from 'path';
import { Request, Response, NextFunction } from 'express';
import sharp from 'sharp';
import { prisma } from '../config/db';
import { fail, success } from '../utils/apiResponse';
import { PRODUCT_THUMBS_DIR, ensureUploadDirs } from '../config/uploadPaths';

const THUMB_WIDTH = 400;

export class UploadController {
  static async uploadProductImages(req: Request, res: Response, next: NextFunction) {
    try {
      const files = req.files as Express.Multer.File[] | undefined;
      if (!files?.length) {
        fail(
          res,
          'No image files received. Ensure the form field name is "files" and Content-Type is multipart.',
          400,
        );
        return;
      }

      ensureUploadDirs();

      const urls: string[] = [];
      const thumbs: string[] = [];

      for (const f of files) {
        const fullUrl = `/uploads/products/${f.filename}`;
        urls.push(fullUrl);

        const thumbPath = path.join(PRODUCT_THUMBS_DIR, f.filename);
        try {
          await sharp(f.path)
            .resize(THUMB_WIDTH, undefined, { withoutEnlargement: true })
            .jpeg({ quality: 70 })
            .toFile(thumbPath);
          thumbs.push(`/uploads/thumbs/${f.filename}`);
        } catch {
          thumbs.push(fullUrl);
        }
      }

      const rawPid = req.body?.productId;
      const productId = typeof rawPid === 'string' ? rawPid.trim() : '';
      if (productId) {
        const vendorId = req.user?.id;
        if (!vendorId) {
          fail(res, 'Unauthorized', 401);
          return;
        }
        const product = await prisma.product.findUnique({ where: { id: productId } });
        if (!product || product.vendorId !== vendorId) {
          fail(res, 'Product not found or not yours', 403);
          return;
        }
        await prisma.product.update({
          where: { id: productId },
          data: { images: [...product.images, ...urls] },
        });
      }

      success(res, { urls, thumbs });
    } catch (err) {
      next(err);
    }
  }
}
